{
  "name": "SoonerCare",
  "eligibility": {
    "age": 65,
    "income_limits": "Varies by program and marital status. For Aged, Blind, and Disabled (ABD) Medicaid (single applicant): income limit applies but exact dollar amount not specified in sources; assessed alongside assets. For Nursing Home Medicaid (single applicant in 2026): under $2,982 per month. For couples or larger households, limits adjust based on spousal impoverishment rules and program. MAGI guidelines apply for some categories but specifics for elderly long-term care use non-MAGI rules. Full table not provided; apply anyway if slightly over as some qualify.[1][6]",
    "asset_limits": "Varies by program. Nursing Home Medicaid (single): $2,000 or less in countable assets. ABD Medicaid (single): $9,950 or less in countable assets. Countable assets include cash, bank accounts, investments, secondary property; exempt assets typically include primary home (under equity limits), one vehicle, personal belongings, burial plots/policies up to certain values. Spousal protections apply if married.[1][6]",
    "other_requirements": ["Oklahoma resident", "US citizen or qualified immigrant", "For long-term care: Nursing Facility Level of Care (NFLOC) or functional needs in ADLs/IADLs (e.g., mobility, bathing, dressing, eating, toileting, shopping, cooking, housekeeping, medication management)", "Blind or disabled (any age) or aged 65+", "Medical/functional assessment for long-term services"][1][2][3][6]
  },
  "benefits": {
    "type": "service",
    "value": "Basic healthcare (physician visits, prescription drugs, ER, short-term hospital); long-term care via Nursing Home Medicaid (nursing facility coverage), HCBS Waivers (home/community-based services like personal care, home modifications), ABD Medicaid (long-term supports based on ADL assessment). No specific dollar amounts or hours stated; covers costs for eligible services through managed care or fee-for-service.[1][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: OKDHSLive.org or MySoonerCare.org", "Phone: not specified in results", "Mail: via OKDHS forms", "In-person: local OKDHS offices for long-term care"][2][5][9],
    "processing_time": "Lengthy and challenging; no specific timeline given[6]",
    "waitlist": null,
    "forms": ["Financial Eligibility Checklist for Long Term Medicaid", "SoonerCare Online Application"],
    "documents": ["Proof of all income/assets (bank statements, pay stubs)", "Social Security, Medicare, health insurance cards", "Proof of citizenship (birth certificate, naturalization, permanent resident card)", "Photo ID (driver's license)", "Life insurance, burial policies/plots/accounts (cash value if owned solely/jointly)"][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Oklahoma residents only",
    "regional_variations": "No regional differences specified; processing may vary locally but not detailed",
    "offices_or_providers": ["Local OKDHS offices for in-person", "Aetna Better Health or SoonerSelect managed care plans if approved"][2][7]
  },
  "official_source": "https://oklahoma.gov/ohca/individuals/mysoonercare/apply-for-soonercare-online/",
  "gotchas": ["Financial rules differ by program (e.g., Nursing Home vs. ABD vs. HCBS Waivers); ABD has higher asset limit but basic coverage only unless long-term needs assessed", "Must meet NFLOC for nursing home/waivers; functional ADL assessment required for long-term benefits", "Spousal impoverishment rules protect community spouse assets/income", "Application requires extensive documentation; consider Medicaid planning if over limits", "Elderly/disabled use OKDHSLive.org, not general MAGI portals", "Process can be lengthy; apply early"][1][6],
  "data_shape_notes": "Eligibility splits by program (Nursing Home: strict $2K assets/$2,982 income; ABD: $9,950 assets); long-term care requires NFLOC/ADL needs; non-MAGI for aged/blind/disabled; spousal rules apply; statewide but local OKDHS handling"
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "At or below 200% of the Federal Poverty Guidelines (varies by household size; exact dollar amounts not specified in sources—check current HHS Poverty Guidelines). Note: Utility-specific programs like OG&E (<$60,000 annual) or PSO (≤$55,000–$65,000 annual, home <2,200 sq ft and ≥10 years old) have different thresholds.[1][2][3][6]",
    "asset_limits": "No asset limits mentioned.[1][2]",
    "other_requirements": ["Low-income Oklahoma households (rent or own).", "Priority to elderly (60+), disabled, families with children (especially ≤5 years), high energy burdens, high residential energy users.[1][2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost home energy efficiency improvements based on assessment/audit, including air sealing, insulation (e.g., attic), duct sealing, door/window repair/replacement, heating system repair/replacement, energy-saving light bulbs, health/safety fixes.[1][2][3][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Community Action Agency (find via Oklahoma Department of Commerce at 405-949-1495 or regional map).[5]", "Utility-specific: OG&E at 405-272-9741 (OKC) or 1-800-272-9741; PSO via provider Titan ES (contact PSO).[3][6]", "In-person/mail via local agencies (e.g., NEOCAA, LIFT).[2][4]"],
    "processing_time": "Not specified statewide; varies by local provider.[1]",
    "waitlist": "Yes, common at local agencies (e.g., NEOCAA has waitlist; applications prioritized by receipt date).[4]",
    "forms": ["Completed application (all pages signed/dated, includes landlord agreement for renters); Verification of Employment or Social Security award letter.[2][4]"],
    "documents": ["Income verification for all household members (employment verification, award letters—no bank statements).", "Recent electric/utility bills (e.g., past 12 months).", "Proof of disability (if applicable).", "Deed (owners) or signed rental agreement (renters).", "ID/proof of residency.[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all 77 counties via local nonprofits/community action agencies.[1][5]",
    "regional_variations": "Implemented by local contractors/agencies with potential differences in wait times, providers, and processes; utility programs (OG&E, PSO) limited to their service areas.[1][3][4][5][6]",
    "offices_or_providers": ["Local Community Action Agencies (contact 405-949-1495 for yours); examples: LIFT Community Action Agency, NEOCAA (NE Oklahoma + Muskogee), Titan ES (PSO).[2][4][5][6]"]
  },
  "official_source": "https://www.okcommerce.gov/weatherization/",
  "gotchas": ["Must contact local agency (not centralized); long waitlists common.", "Priority-based selection, not guaranteed service.", "Utility programs have separate, stricter criteria (e.g., income caps, home size/age).", "Renters need landlord permission.[1][2][3][4][6]"],
  "data_shape_notes": "Decentralized via 77-county local providers with priority tiers; income at 200% FPL; no statewide application portal—agency-specific."
}

{
  "name": "State Health Insurance Counseling Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No strict income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries, their families, and caregivers. No specific dollar amounts or household size tables provided.[1][2][3]",
    "asset_limits": "No asset limits mentioned.[1][2][3]",
    "other_requirements": ["Must be a Medicare beneficiary (typically age 65+ or under 65 with disabilities), family member, or caregiver. Dually eligible for Medicare and Medicaid also supported. No formal application for eligibility to receive counseling services."][1][2][3]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling, education, and assistance on Medicare (Parts A, B, C, D), Medigap, Medicare Savings Programs (QMB, SLMB, QI), Extra Help/Low-Income Subsidy, Medicaid, long-term care insurance, prescription drug assistance, appeals, coverage options, and protection from overpayment. Includes printed materials, referrals, outreach presentations, enrollment events, and health fairs. Provided by trained volunteer and paid counselors.[1][2][3][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-763-2828 (in-state toll-free) or 405-521-6628 (out-of-state/direct line)", "Website: https://www.oid.ok.gov/consumers/information-for-seniors/senior-health-insurance-counseling-program-ship/", "In-person or phone counseling appointments arranged via contact (local providers via state program)", "No formal application form; contact to schedule counseling session."[2][4][7]],
    "processing_time": "No formal processing; counseling appointments scheduled upon contact, typically immediate or short wait for session.[2]",
    "waitlist": null,
    "forms": ["No specific forms required to access counseling; counselors assist with applications for related programs like Medicare Savings or Extra Help during sessions."],
    "documents": ["No documents needed to start counseling; for assistance with applications (e.g., Medicare Savings Programs, Extra Help), prepare Medicare card, income statements, and relevant insurance details."][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Oklahoma Medicare beneficiaries.",
    "regional_variations": "Delivered through local networks of trained counselors at area agencies on aging, community organizations, and senior centers, but core services uniform statewide. No specific regional wait time or provider differences noted.[1][3][6]",
    "offices_or_providers": ["Administered by Oklahoma Insurance Department (OID); local access via community-based counselors and events."][1][4][7]
  },
  "official_source": "https://www.oid.ok.gov/consumers/information-for-seniors/senior-health-insurance-counseling-program-ship/[1]",
  "gotchas": ["Not a healthcare or financial aid program itself—provides counseling only, not direct payments or medical services.", "Open to all Medicare beneficiaries, not just low-income; people miss that it's free and available regardless of income.", "Requires contacting to schedule; no walk-in without appointment.", "Counselors help apply for income-based programs like Extra Help, but those have separate eligibility (not detailed here).", "Focuses on Medicare navigation; for non-Medicare issues, may refer elsewhere."][1][2][5],
  "data_shape_notes": "no income test or asset limits for counseling access; prioritizes limited-income and disabled beneficiaries but open to all; services via phone/in-person statewide with volunteer networks; no formal application or waitlist."
}

{
  "name": "Long-term care ombudsman",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to any resident or family regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must be a resident of a certified long-term care facility in Oklahoma (nursing facility, assisted living center, residential care home, or specialized facility licensed under Oklahoma Statutes Title 63), or a family member/friend acting on their behalf with resident consent for investigations.", "Complaints or assistance requests related to facility care, rights, or quality of life."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Receives and investigates complaints from residents, families, or friends; mediates resolutions with facility staff; explores problems and makes recommendations for corrective action with resident consent; provides information on facilities, resident rights, laws/regulations, advance directives, transfers/discharges; improves quality of life and care; no fixed dollar amounts or hours—services provided as needed per case.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-211-2116 or local (405) 521-6734 (M-F 8am-5pm)", "Email: ombudsmanfax@ltco.ok.gov (for State Ombudsman Bill Whited)", "In-person: Contact local Area Agency on Aging Ombudsman supervisor via statewide phone line for regional offices"],
    "processing_time": "Attempts to resolve complaints through communication; no formal processing timeline specified, but focuses on prompt mediation and investigation.",
    "waitlist": null,
    "forms": ["No specific application forms required; complaints handled via phone/email or verbal report with resident consent documented if needed."],
    "documents": ["Resident consent (written or oral, documented by ombudsman) for investigations/disclosures; optional: details of complaint, facility name/address, resident info."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to certified long-term care facilities statewide; no county restrictions for residents.",
    "regional_variations": "Program operates through local Area Agencies on Aging (e.g., INCOG in Tulsa/Creek/Osage Counties for regional supervision and volunteers); volunteer availability and supervisors may vary by region, but core services uniform.",
    "offices_or_providers": ["State Office: Oklahoma Attorney General's Office, contact via 1-800-211-2116; Local: Area Agencies on Aging (e.g., INCOG Agency on Aging in Tulsa area)"]
  },
  "official_source": "https://oklahoma.gov/oag/about/divisions/ltco.html",
  "gotchas": ["Requires resident consent (written/oral) for file access or investigations—cannot act without it unless court-ordered.", "Not a regulatory body or substitute for Oklahoma State Department of Health complaints (1-800-747-8419 for licensing violations).", "Staff/volunteers must be free of conflicts (e.g., not employed by facilities, Medicaid eligibility roles, or protective services).", "Families can contact pre-admission for facility info but services focus on current residents.", "Not financial aid or direct care—purely advocacy and mediation."],
  "data_shape_notes": "no income/asset test; consent-driven advocacy only for long-term care facility residents; volunteer-supported via regional Area Agencies on Aging; distinct from health department enforcement or Medicaid programs."
}
